/**
 * Base64-encoded ExxSend logo mark, for embedding directly into the
 * transaction receipt's HTML template (expo-print's HTML-to-PDF renderer
 * can't reliably load local/external image URIs, so the logo needs to be
 * inlined as a data URI rather than referenced by file path).
 *
 * Source: assets/images/icons/icon.png — the real "EX" wordmark, blue on
 * a white/transparent background. This is the correct, visible variant for
 * a plain white receipt header.
 *
 * NOTE on past mistakes — there are THREE differently-colored files with
 * overlapping names in this project, easy to grab the wrong one:
 *   - assets/images/android-icon-foreground.png      → WRONG, old/unused, blue chevron
 *   - assets/images/icons/android-icon-foreground.png → WHITE-on-transparent
 *     (correct for a colored/dark background, invisible on white)
 *   - assets/images/icons/icon.png                    → THIS ONE, blue "EX"
 *     wordmark on white/transparent — correct for a plain white background.
 */
export const EXXSEND_LOGO_BASE64 = "";
